  stimulus_type = NULL,
  options = '[{"id":"A","text":"The author’s book, a collection of essays on the history of the English language, was a critical, and commercial success.","is_correct":true,"explanation":"Choice A matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Compare this option against the grammar or logic rule tested by the stem before selecting a final answer."},{"id":"B","text":"The author’s book a collection of essays on the history of the English language, was a critical and commercial success.","is_correct":false,"explanation":"Choice B is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Compare this option against the grammar or logic rule tested by the stem before selecting a final answer."},{"id":"C","text":"The author’s book, a collection of essays on the history of the English language was a critical and commercial success.","is_correct":false,"explanation":"Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Compare this option against the grammar or logic rule tested by the stem before selecting a final answer."},{"id":"D","text":"The author’s book, a collection of essays on the history of the English language was a critical, and commercial success.","is_correct":false,"explanation":"Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Compare this option against the grammar or logic rule tested by the stem before selecting a final answer."}]'::jsonb,
